import React from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight, Tag, User, Calendar } from 'lucide-react';

interface CardProps {
  to: string;
  image: string;
  title: string;
  description: string;
  category?: string;
  meta?: {
    author?: string;
    date?: string;
  };
  tags?: string[];
}

const Card: React.FC<CardProps> = ({ to, image, title, description, category, meta, tags }) => {
  return (
    <Link 
      to={to} 
      className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-all group flex flex-col h-full"
    >
      <div className="relative h-48 overflow-hidden">
        <img 
          src={image} 
          alt={title} 
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
        />
        {category && (
          <div className="absolute top-4 left-4">
            <span className="bg-blue-600 text-white text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full shadow-lg">
              {category}
            </span>
          </div>
        )}
      </div>
      <div className="p-6 flex flex-col flex-grow">
        <h3 className="text-lg font-bold text-slate-900 group-hover:text-blue-600 transition-colors mb-2 leading-tight">
          {title}
        </h3>
        <p className="text-slate-600 text-sm mb-4 line-clamp-3">
          {description}
        </p>

        <div className="mt-auto space-y-3">
          {tags && (
            <div className="flex flex-wrap gap-2">
              {tags.slice(0, 2).map((tag, idx) => (
                <span key={idx} className="inline-flex items-center gap-1 text-[11px] text-slate-500 bg-slate-100 px-2 py-0.5 rounded">
                  <Tag size={10} />
                  {tag}
                </span>
              ))}
            </div>
          )}

          <div className="flex items-center justify-between pt-4 border-t border-slate-100">
            <div className="flex flex-col gap-1">
              {meta?.author && (
                <span className="text-[11px] text-slate-400 flex items-center gap-1">
                  <User size={12} /> {meta.author}
                </span>
              )}
              {meta?.date && (
                <span className="text-[11px] text-slate-400 flex items-center gap-1">
                  <Calendar size={12} /> {meta.date}
                </span>
              )}
            </div>
            <div className="text-blue-600 group-hover:translate-x-1 transition-transform">
              <ArrowRight size={18} />
            </div>
          </div>
        </div>
      </div>
    </Link>
  );
};

