import React, { useState } from 'react';
import { materials } from '../data';
import Card from '../components/Card';
import { Category } from '../types';
import { Search, Filter } from 'lucide-react';

const MaterialsList: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Category | 'All'>('All');

  const filteredMaterials = materials.filter(mat => {
    const matchesSearch = mat.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          mat.description.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || mat.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const categories = ['All', ...Object.values(Category)];

  return (
    <div className="py-12 bg-slate-50 min-h-screen">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-12">
          <h1 className="text-4xl font-bold text-slate-900 mb-4">Pedagogické materiály</h1>
          <p className="text-slate-600 text-lg">Inspirujte se materiály od kolegů nebo sdílejte ty své.</p>
        </div>

        {/* Filters */}
        <div className="flex flex-col md:flex-row gap-4 mb-10 items-center">
          <div className="relative flex-grow w-full">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Vyhledat materiál..." 
              className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all shadow-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto w-full md:w-auto pb-2 md:pb-0 no-scrollbar">
            {categories.map((cat) => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat as any)}
                className={`px-4 py-2.5 rounded-xl whitespace-nowrap text-sm font-medium border transition-all ${
                  selectedCategory === cat 
                    ? 'bg-blue-600 border-blue-600 text-white shadow-md' 
                    : 'bg-white border-slate-200 text-slate-600 hover:border-blue-400'
                }`}
              >
                {cat === 'All' ? 'Vše' : cat}
              </button>
            ))}
          </div>
        </div>

        {filteredMaterials.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredMaterials.map((mat) => (
              <Card 
                key={mat.id}
                to={`/materialy/${mat.id}`}
                image={mat.thumbnail}
                title={mat.title}
                description={mat.description}
                category={mat.category}
                tags={mat.tags}
                meta={{ author: mat.author, date: mat.date }}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-20">
            <div className="bg-slate-100 p-6 rounded-full inline-block mb-4 text-slate-400">
              <Search size={48} />
            </div>
            <h3 className="text-xl font-bold text-slate-900 mb-2">Nebyly nalezeny žádné materiály</h3>
            <p className="text-slate-500">Zkuste změnit klíčová slova nebo filtr.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default MaterialsList;

