import React from 'react';
import { 
  Terminal, 
  Brain, 
  Cpu, 
  ShieldAlert, 
  MailWarning, 
  CircuitBoard, 
  Binary,
  Code,
  Lock,
  Zap,
  BookOpen,
  AppWindow,
  FileCode
} from 'lucide-react';
import { Category } from '../types';

interface IconRendererProps {
  name: string;
  size?: number;
  className?: string;
  category?: Category;
}

const IconRenderer: React.FC<IconRendererProps> = ({ name, size = 24, className = '', category }) => {
  const getIcon = () => {
    switch (name) {
      case 'terminal': return <Terminal size={size} />;
      case 'brain': return <Brain size={size} />;
      case 'cpu': return <Cpu size={size} />;
      case 'shield-lock': return <Lock size={size} />;
      case 'mail-warning': return <MailWarning size={size} />;
      case 'circuit-board': return <CircuitBoard size={size} />;
      case 'binary': return <Binary size={size} />;
      case 'code': return <Code size={size} />;
      case 'zap': return <Zap size={size} />;
      case 'book': return <BookOpen size={size} />;
      default: return <FileCode size={size} />;
    }
  };

  const getBgColor = () => {
    switch (category) {
      case Category.PROGRAMMING: return 'bg-blue-50 text-blue-600 border-blue-100';
      case Category.AI: return 'bg-purple-50 text-purple-600 border-purple-100';
      case Category.HARDWARE: return 'bg-orange-50 text-orange-600 border-orange-100';
      case Category.CYBERSECURITY: return 'bg-red-50 text-red-600 border-red-100';
      case Category.ALGORITHMS: return 'bg-emerald-50 text-emerald-600 border-emerald-100';
      case Category.OFFICE: return 'bg-indigo-50 text-indigo-600 border-indigo-100';
      default: return 'bg-slate-50 text-slate-600 border-slate-100';
    }
  };

  return (
    <div className={`flex items-center justify-center rounded-2xl border transition-all duration-300 ${getBgColor()} ${className}`}>
      {getIcon()}
    </div>
  );
};

export default IconRenderer;

